import json
import pathlib
import re

import pytest

AC_UID = "ac02_injection_proof"
AC_TYPE = "data"

REPO_ROOT = pathlib.Path(__file__).resolve().parents[3]
QA_REPORT = REPO_ROOT / "docs" / "dev" / "qa-report-20260526-053746.json"

REQUIRED_FIELDS = [
    "rank_acknowledged",
    "range_acknowledged",
    "recent_events_digest_acknowledged",
    "score_injection_action",
]

DIGEST_RE = re.compile(r"^[0-9a-f]{8}$")
MIN_ACTION_LEN = 20
FORBIDDEN_PLACEHOLDERS = {
    "no action needed", "no action", "none", "n/a", "na", "nothing",
    "skip", "no-op", "tbd", "ok", "acknowledged",
}


def test_AC_02_injection_proof_fields_present_and_valid():
    """
    GIVEN: score-inject.sh emits INJECTION_PROOF block to QA subagent dispatch.
    WHEN:  QA produces its qa-report JSON for this cycle.
    THEN:  qa-report contains all 4 fields: rank_acknowledged (non-empty
           string), range_acknowledged (non-empty string),
           recent_events_digest_acknowledged (8-char hex),
           score_injection_action (non-empty string >= 20 chars, not a
           forbidden placeholder).
    """
    if not QA_REPORT.exists():
        # AC-02 is verified at QA runtime — this cycle's QA dispatch produces
        # the qa-report-20260526-053746.json with the 4 INJECTION_PROOF fields.
        # Dev runs BEFORE QA in the workflow, so the report file does not yet
        # exist at dev-time. Skip with a clear marker.
        #
        # CRITICAL FOR QA (codex iter-3 F2 closure): QA Phase 5 MUST re-run this
        # test AFTER the qa-report-20260526-053746.json is written. A SKIP at
        # dev-time is acceptable; a SKIP at QA-Phase-5-final-verification time
        # MUST be treated as a FAIL on this AC. The Phase 5 manifest verification
        # step is responsible for the rerun and must not accept skip→pass.
        pytest.skip(
            f"qa-report not yet produced at {QA_REPORT}; "
            f"AC-02 is a runtime check executed by QA Phase 5 after dispatch. "
            f"QA MUST re-run this test after writing the report and treat any "
            f"remaining skip as FAIL (per codex iter-3 F2)."
        )

    with open(QA_REPORT) as fh:
        report = json.load(fh)

    # All four fields MUST be present.
    missing = [f for f in REQUIRED_FIELDS if f not in report]
    assert not missing, f"qa-report missing INJECTION_PROOF fields: {missing}"

    rank = report["rank_acknowledged"]
    rng = report["range_acknowledged"]
    digest = report["recent_events_digest_acknowledged"]
    action = report["score_injection_action"]

    # rank_acknowledged: non-empty string
    assert isinstance(rank, str) and rank.strip(), (
        f"rank_acknowledged must be non-empty string, got {rank!r}"
    )

    # range_acknowledged: non-empty string
    assert isinstance(rng, str) and rng.strip(), (
        f"range_acknowledged must be non-empty string, got {rng!r}"
    )

    # recent_events_digest_acknowledged: 8-char hex
    assert isinstance(digest, str) and DIGEST_RE.match(digest), (
        f"recent_events_digest_acknowledged must match ^[0-9a-f]{{8}}$, "
        f"got {digest!r}"
    )

    # score_injection_action: non-empty, >= 20 chars, not a placeholder
    assert isinstance(action, str), (
        f"score_injection_action must be string, got type {type(action)}"
    )
    assert len(action) >= MIN_ACTION_LEN, (
        f"score_injection_action must be >= {MIN_ACTION_LEN} chars, "
        f"got len={len(action)}: {action!r}"
    )
    assert action.strip().lower() not in FORBIDDEN_PLACEHOLDERS, (
        f"score_injection_action is a forbidden placeholder: {action!r}"
    )
